from cms.menu_bases import CMSAttachMenu
from menus.base import NavigationNode
from menus.menu_pool import menu_pool


class CatalogMenu(CMSAttachMenu):
    name = _("Catalog Menu")

    def get_nodes(self, request):
        try:
            if self.instance.publisher_is_draft:
                productpage_set = self.instance.publisher_public.productpage_set
            else:
                productpage_set = self.instance.productpage_set
        except AttributeError:
            return []
        nodes = []
        with override(request.LANGUAGE_CODE):
            for id, productpage in enumerate(productpage_set.all(), 1):
                node = NavigationNode(
                    title=productpage.product.product_name,
                    url=productpage.product.get_absolute_url(),
                    id=id,
                )
                if hasattr(productpage.product, 'slug'):
                    node.path = productpage.product.slug
                nodes.append(node)
        return nodes

menu_pool.register_menu(CatalogMenu)

class Registry:
    def __init__(self):
        self._registry = {}
        self._field_registry = {}

    def register(self, cls):
        from .types import DjangoObjectType

        assert issubclass(
            cls, DjangoObjectType
        ), f'Only DjangoObjectTypes can be registered, received "{cls.__name__}"'
        assert cls._meta.registry == self, "Registry for a Model have to match."
        # assert self.get_type_for_model(cls._meta.model) == cls, (
        #     'Multiple DjangoObjectTypes registered for "{}"'.format(cls._meta.model)
        # )
        if not getattr(cls._meta, "skip_registry", False):
            self._registry[cls._meta.model] = cls

    def get_type_for_model(self, model):
        return self._registry.get(model)

    def register_converted_field(self, field, converted):
        self._field_registry[field] = converted

    def get_converted_field(self, field):
        return self._field_registry.get(field)


registry = None


def get_global_registry():
    global registry
    if not registry:
        registry = Registry()
    return registry


def reset_global_registry():
    global registry
    registry = None

