from hc.integrations.slack.transport import Slackalike
from hc.lib import curl


class Discord(Slackalike):
    @classmethod
    def raise_for_response(cls, response: curl.Response) -> NoReturn:
        message = f"Received status code {response.status_code}"
        # Consider 404 a permanent failure
        permanent = response.status_code == 404
        raise TransportError(message, permanent=permanent)

    def notify(self, flip: Flip, notification: Notification) -> None:
        url = self.channel.discord_webhook_url + "/slack"

        prepared_payload = self.payload(flip)
        self.post(url, json=prepared_payload)

    def fix_asterisks(self, s: str) -> str:
        # In Discord notifications asterisks should be escaped with a backslash
        return s.replace("*", r"\*")

import re

from django.core.exceptions import ValidationError
from django.utils.translation import gettext as _


def validate_domain(domain: str | None) -> None:
    if domain is None or len(domain) == 0:
        raise ValidationError(_("Domain can't be empty."))
    if "." not in domain:
        raise ValidationError(_("Domain must have at least one dot (.)"))
    if len(domain) > 255:
        raise ValidationError(_("Domain is too long"))
    if domain[0] == "." or domain[-1] == ".":
        raise ValidationError(_("Domain cannot start or end with a dot (.)"))
    for subdomain in domain.split("."):
        if not subdomain:
            raise ValidationError(_("Consecutive '.' are not allowed."))
        if subdomain[0] == "-" or subdomain[-1] == "-":
            raise ValidationError(_("Subdomains cannot start or end with a '-'."))
        if not re.match(r"^[a-z0-9-]*$", subdomain):
            raise ValidationError(_("Domain can only have letters, numbers, '.' and '-'s."))

