from django_q.models import Schedule
from django_q.tasks import schedule

from api.services import SERVICES, start_service


class Command(BaseCommand):
    help = "Start one of the services."

    # Define all the services that can be started
    def add_arguments(self, parser):
        parser.add_argument(
            "service",
            type=str,
            help="The service to start",
            choices=[
                SERVICES.keys(),
                "all",
            ],
        )

    def handle(self, *args, **kwargs):
        service = kwargs["service"]
        if service == "all":
            for svc in SERVICES.keys():
                start_service(svc)
            if not Schedule.objects.filter(func="api.services.check_services").exists():
                schedule(
                    "api.services.check_services",
                    schedule_type=Schedule.MINUTES,
                    minutes=1,
                )
        else:
            start_service(service)

from haystack.query import SearchQuerySet

from blog.models import Article, Category


class BlogApi:
    def __init__(self):
        self.searchqueryset = SearchQuerySet()
        self.searchqueryset.auto_query('')
        self.__max_takecount__ = 8

    def search_articles(self, query):
        sqs = self.searchqueryset.auto_query(query)
        sqs = sqs.load_all()
        return sqs[:self.__max_takecount__]

    def get_category_lists(self):
        return Category.objects.all()

    def get_category_articles(self, categoryname):
        articles = Article.objects.filter(category__name=categoryname)
        if articles:
            return articles[:self.__max_takecount__]
        return None

    def get_recent_articles(self):
        return Article.objects.all()[:self.__max_takecount__]

